@app.route("/api/users", methods=["POST"])
def create_user():
    """Create a new user profile."""
    data = request.get_json()

    if not data:
        return jsonify({"error": "No data provided"}), 400

    required_fields = ["username", "email", "full_name"]
    for field in required_fields:
        if field not in data:
            return jsonify({"error": f"Missing required field: {field}"}), 400

    user = {
        "username": data["username"],
        "email": data["email"],
        "full_name": data["full_name"],
        "bio": data.get("bio", ""),
        "avatar_url": data.get("avatar_url", ""),
        "role": data.get("role", "author"),
        "preferences": data.get("preferences", {}),
        "social_links": data.get("social_links", {}),
        "created_at": datetime.utcnow(),
        "updated_at": datetime.utcnow(),
        "is_active": True,
    }

    try:
        result = users_collection.insert_one(user)
        user["_id"] = str(result.inserted_id)
        user["created_at"] = user["created_at"].isoformat()
        user["updated_at"] = user["updated_at"].isoformat()
        return jsonify({"message": "User created successfully", "user": user}), 201
    except Exception as e:
        if "duplicate key" in str(e):
            return jsonify({"error": "Username or email already exists"}), 409
        return jsonify({"error": str(e)}), 500


@app.route("/api/users", methods=["GET"])
def get_users():
    """Get all users with optional filtering."""
    role = request.args.get("role")
    is_active = request.args.get("is_active")
    page = int(request.args.get("page", 1))
    per_page = int(request.args.get("per_page", 10))

    query = {}
    if role:
        query["role"] = role
    if is_active is not None:
        query["is_active"] = is_active.lower() == "true"

    skip = (page - 1) * per_page
    total = users_collection.count_documents(query)
    users = list(users_collection.find(query).skip(skip).limit(per_page).sort("created_at", DESCENDING))

    return jsonify({
        "users": parse_json(users),
        "total": total,
        "page": page,
        "per_page": per_page,
        "total_pages": (total + per_page - 1) // per_page,
    }), 200


@app.route("/api/users/<user_id>", methods=["GET"])
def get_user(user_id):
    """Get a single user profile by ID."""
    try:
        user = users_collection.find_one({"_id": ObjectId(user_id)})
    except Exception:
        return jsonify({"error": "Invalid user ID"}), 400

    if not user:
        return jsonify({"error": "User not found"}), 404

    return jsonify({"user": parse_json(user)}), 200


@app.route("/api/users/<user_id>", methods=["PUT"])
def update_user(user_id):
    """Update a user profile."""
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400

    # Prevent updating certain fields
    protected_fields = ["_id", "created_at"]
    update_data = {k: v for k, v in data.items() if k not in protected_fields}
    update_data["updated_at"] = datetime.utcnow()

    try:
        result = users_collection.update_one(
            {"_id": ObjectId(user_id)},
            {"$set": update_data}
        )
    except Exception as e:
        if "duplicate key" in str(e):
            return jsonify({"error": "Username or email already exists"}), 409
        return jsonify({"error": str(e)}), 500

    if result.matched_count == 0:
        return jsonify({"error": "User not found"}), 404

    updated_user = users_collection.find_one({"_id": ObjectId(user_id)})
    return jsonify({"message": "User updated successfully", "user": parse_json(updated_user)}), 200


@app.route("/api/users/<user_id>", methods=["DELETE"])
def delete_user(user_id):
    """Soft delete a user profile."""
    try:
        result = users_collection.update_one(
            {"_id": ObjectId(user_id)},
            {"$set": {"is_active": False, "updated_at": datetime.utcnow()}}
        )
    except Exception:
        return jsonify({"error": "Invalid user ID"}), 400

    if result.matched_count == 0:
        return jsonify({"error": "User not found"}), 404

    return jsonify({"message": "User deactivated successfully"}), 200


