@app.route("/api/analytics/author-stats", methods=["GET"])
def author_stats():
    """Aggregation: Get statistics per author."""
    pipeline = [
        {
            "$group": {
                "_id": "$author_id",
                "total_documents": {"$sum": 1},
                "total_views": {"$sum": "$views"},
                "total_likes": {"$sum": "$likes"},
                "avg_views": {"$avg": "$views"},
                "avg_likes": {"$avg": "$likes"},
                "published_count": {
                    "$sum": {"$cond": [{"$eq": ["$status", "published"]}, 1, 0]}
                },
                "draft_count": {
                    "$sum": {"$cond": [{"$eq": ["$status", "draft"]}, 1, 0]}
                },
                "categories": {"$addToSet": "$category"},
            }
        },
        {
            "$lookup": {
                "from": "users",
                "localField": "_id",
                "foreignField": "_id",
                "as": "author_info"
            }
        },
        {"$unwind": {"path": "$author_info", "preserveNullAndEmptyArrays": True}},
        {
            "$project": {
                "author_id": "$_id",
                "author_name": "$author_info.full_name",
                "author_username": "$author_info.username",
                "total_documents": 1,
                "total_views": 1,
                "total_likes": 1,
                "avg_views": {"$round": ["$avg_views", 2]},
                "avg_likes": {"$round": ["$avg_likes", 2]},
                "published_count": 1,
                "draft_count": 1,
                "categories": 1,
            }
        },
        {"$sort": {"total_documents": -1}},
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({"author_stats": parse_json(results)}), 200


@app.route("/api/analytics/category-stats", methods=["GET"])
def category_stats():
    """Aggregation: Get statistics per category."""
    pipeline = [
        {
            "$group": {
                "_id": "$category",
                "total_documents": {"$sum": 1},
                "total_views": {"$sum": "$views"},
                "total_likes": {"$sum": "$likes"},
                "avg_views": {"$avg": "$views"},
                "unique_authors": {"$addToSet": "$author_id"},
                "statuses": {
                    "$push": "$status"
                },
            }
        },
        {
            "$project": {
                "category": "$_id",
                "total_documents": 1,
                "total_views": 1,
                "total_likes": 1,
                "avg_views": {"$round": ["$avg_views", 2]},
                "unique_author_count": {"$size": "$unique_authors"},
                "published_count": {
                    "$size": {
                        "$filter": {
                            "input": "$statuses",
                            "cond": {"$eq": ["$$this", "published"]}
                        }
                    }
                },
            }
        },
        {"$sort": {"total_documents": -1}},
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({"category_stats": parse_json(results)}), 200


