@app.route("/api/analytics/top-documents", methods=["GET"])
def top_documents():
    """Aggregation: Get top documents by views or likes."""
    metric = request.args.get("metric", "views")  # views or likes
    limit = int(request.args.get("limit", 10))
    status = request.args.get("status", "published")

    sort_field = f"${metric}" if metric in ["views", "likes"] else "$views"

    pipeline = [
        {"$match": {"status": status}},
        {
            "$lookup": {
                "from": "users",
                "localField": "author_id",
                "foreignField": "_id",
                "as": "author_info"
            }
        },
        {"$unwind": {"path": "$author_info", "preserveNullAndEmptyArrays": True}},
        {
            "$project": {
                "title": 1,
                "category": 1,
                "tags": 1,
                "views": 1,
                "likes": 1,
                "comment_count": {"$size": {"$ifNull": ["$comments", []]}},
                "author_name": "$author_info.full_name",
                "author_username": "$author_info.username",
                "created_at": 1,
                "published_at": 1,
            }
        },
        {"$sort": {metric: -1}},
        {"$limit": limit},
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({"top_documents": parse_json(results)}), 200


