@app.route("/api/search", methods=["GET"])
def search_documents():
    """Full text search across documents."""
    query_text = request.args.get("q", "")
    status = request.args.get("status", "published")
    page = int(request.args.get("page", 1))
    per_page = int(request.args.get("per_page", 10))

    if not query_text:
        return jsonify({"error": "Search query 'q' is required"}), 400

    search_query = {
        "$text": {"$search": query_text},
        "status": status,
    }

    skip = (page - 1) * per_page
    total = documents_collection.count_documents(search_query)

    documents = list(
        documents_collection.find(
            search_query,
            {"score": {"$meta": "textScore"}}
        )
        .sort([("score", {"$meta": "textScore"})])
        .skip(skip)
        .limit(per_page)
    )

    return jsonify({
        "results": parse_json(documents),
        "total": total,
        "page": page,
        "per_page": per_page,
        "query": query_text,
    }), 200


# =====================
# Bulk Operations
# =====================

@app.route("/api/documents/bulk-update", methods=["POST"])
def bulk_update_documents():
    """Bulk update document status."""
    data = request.get_json()
    if not data or "document_ids" not in data or "status" not in data:
        return jsonify({"error": "document_ids and status are required"}), 400

    valid_statuses = ["draft", "published", "archived"]
    if data["status"] not in valid_statuses:
        return jsonify({"error": f"Invalid status. Must be one of: {valid_statuses}"}), 400

    try:
        object_ids = [ObjectId(doc_id) for doc_id in data["document_ids"]]
    except Exception:
        return jsonify({"error": "Invalid document ID in list"}), 400

    update_fields = {
        "status": data["status"],
        "updated_at": datetime.utcnow(),
    }

    if data["status"] == "published":
        update_fields["published_at"] = datetime.utcnow()

    result = documents_collection.update_many(
        {"_id": {"$in": object_ids}},
        {"$set": update_fields}
    )

    return jsonify({
        "message": f"Updated {result.modified_count} documents",
        "matched": result.matched_count,
        "modified": result.modified_count,
    }), 200


